@page "/chat"
@using sv_5bf7cc44c45a4cbbadf4531cb193fd67.Services
@inject IChatService ChatService
@rendermode InteractiveServer

<PageTitle>Chat</PageTitle>

<div class="chat-layout">
    @* ── Left Sidebar ── *@
    <aside class="sidebar">
        <h3 class="sidebar-title">Channels</h3>
        <ul class="channel-list">
            @if (_channels is not null)
            {
                @foreach (var ch in _channels)
                {
                    <li class="channel-item @(ch.Id == _activeChannelId ? "active" : "")"
                        @onclick="() => SelectChannelAsync(ch)">
                        <div class="channel-header-row">
                            <span class="channel-name"># @ch.Name</span>
                            @if (ch.UnreadCount > 0)
                            {
                                <span class="unread-badge">@ch.UnreadCount</span>
                            }
                        </div>
                        @if (!string.IsNullOrWhiteSpace(ch.Description))
                        {
                            <span class="channel-desc">@Truncate(ch.Description, 48)</span>
                        }
                    </li>
                }
            }
        </ul>
    </aside>

    @* ── Main Message Area ── *@
    <section class="main-area @(_threadOpen ? "" : "main-area--full")">
        @if (_activeChannel is not null)
        {
            <header class="main-header">
                <h2 class="main-channel-name"># @_activeChannel.Name</h2>
                <span class="main-channel-desc">@_activeChannel.Description</span>
            </header>

            <div class="message-list" @onscroll="OnMainScrollAsync" @ref="_messageListRef">
                @if (_loadingMore)
                {
                    <div class="loading-indicator">Loading older messages…</div>
                }
                @if (_messages is not null)
                {
                    @foreach (var msg in _messages)
                    {
                        <div class="message-card" @onmouseenter="() => _hoveredMessageId = msg.Id"
                             @onmouseleave="() => { if (_hoveredMessageId == msg.Id) _hoveredMessageId = null; }">
                            <div class="message-meta">
                                <span class="msg-author">@msg.Author</span>
                                <span class="msg-time">@FormatRelativeTime(msg.SentAt)</span>
                            </div>
                            <div class="msg-content">@msg.Content</div>

                            @* Reactions *@
                            @if (msg.Reactions?.Count > 0)
                            {
                                <div class="reactions-row">
                                    @foreach (var r in msg.Reactions)
                                    {
                                        <button class="reaction-badge" title="@string.Join(", ", r.Users)"
                                                @onclick="() => AddReactionAsync(msg.Id, r.Emoji)">
                                            @r.Emoji @r.Users.Count
                                        </button>
                                    }
                                </div>
                            }

                            @* Thread starter link *@
                            @if (_threadSummaries.TryGetValue(msg.Id, out var ts))
                            {
                                <button class="thread-link" @onclick="() => OpenThreadAsync(msg)">
                                    @ts.ReplyCount @(ts.ReplyCount == 1 ? "reply" : "replies")
                                </button>
                            }

                            @* Hover actions *@
                            @if (_hoveredMessageId == msg.Id)
                            {
                                <div class="message-actions">
                                    <button class="action-btn" title="Reply in thread"
                                            @onclick="() => OpenThreadAsync(msg)">💬 Reply</button>
                                    <div class="emoji-picker-wrapper">
                                        <button class="action-btn" title="Add reaction"
                                                @onclick="() => ToggleEmojiPicker(msg.Id)">🙂 React</button>
                                        @if (_emojiPickerMessageId == msg.Id)
                                        {
                                            <div class="emoji-picker">
                                                @foreach (var emoji in _commonEmojis)
                                                {
                                                    <button class="emoji-option"
                                                            @onclick="() => AddReactionAsync(msg.Id, emoji)">@emoji</button>
                                                }
                                            </div>
                                        }
                                    </div>
                                </div>
                            }
                        </div>
                    }
                }
            </div>

            <div class="compose-area">
                <textarea class="compose-input" placeholder="Type a message…" @bind="_newMessage"
                          @onkeydown="OnComposeKeyDownAsync" rows="2"></textarea>
                <button class="send-btn" disabled="@string.IsNullOrWhiteSpace(_newMessage)"
                        @onclick="SendMessageAsync">Send</button>
            </div>
        }
        else
        {
            <div class="no-channel">Select a channel to start chatting</div>
        }
    </section>

    @* ── Right Thread Panel ── *@
    @if (_threadOpen && _threadRootMessage is not null)
    {
        <aside class="thread-panel">
            <header class="thread-header">
                <h3>Thread</h3>
                <button class="close-btn" @onclick="CloseThread" title="Close thread">✕</button>
            </header>

            <div class="thread-root-quote">
                <span class="msg-author">@_threadRootMessage.Author</span>
                <span class="msg-time">@FormatRelativeTime(_threadRootMessage.SentAt)</span>
                <p class="msg-content">@_threadRootMessage.Content</p>
            </div>

            <div class="thread-replies">
                @if (_threadReplies is not null)
                {
                    @foreach (var reply in _threadReplies)
                    {
                        <div class="message-card">
                            <div class="message-meta">
                                <span class="msg-author">@reply.Author</span>
                                <span class="msg-time">@FormatRelativeTime(reply.SentAt)</span>
                            </div>
                            <div class="msg-content">@reply.Content</div>

                            @if (reply.Reactions?.Count > 0)
                            {
                                <div class="reactions-row">
                                    @foreach (var r in reply.Reactions)
                                    {
                                        <button class="reaction-badge" title="@string.Join(", ", r.Users)"
                                                @onclick="() => AddReactionAsync(reply.Id, r.Emoji)">
                                            @r.Emoji @r.Users.Count
                                        </button>
                                    }
                                </div>
                            }
                        </div>
                    }
                }
            </div>

            <div class="compose-area">
                <textarea class="compose-input" placeholder="Reply…" @bind="_threadReplyText"
                          @onkeydown="OnThreadReplyKeyDownAsync" rows="2"></textarea>
                <button class="send-btn" disabled="@string.IsNullOrWhiteSpace(_threadReplyText)"
                        @onclick="SendThreadReplyAsync">Reply</button>
            </div>
        </aside>
    }
</div>

@code {
    // ── Constants ──
    private const int PageSize = 30;
    private static readonly string[] _commonEmojis = ["👍", "❤️", "😂", "🎉", "🚀", "👀"];

    // ── Channel state ──
    private List<Channel>? _channels;
    private int? _activeChannelId;
    private Channel? _activeChannel;

    // ── Message state ──
    private List<Message>? _messages;
    private int _skip;
    private bool _loadingMore;
    private bool _allLoaded;
    private ElementReference _messageListRef;

    // ── Thread state ──
    private bool _threadOpen;
    private Message? _threadRootMessage;
    private List<Message>? _threadReplies;
    private string _threadReplyText = string.Empty;
    private Dictionary<int, ThreadSummary> _threadSummaries = new();

    // ── Hover / emoji picker ──
    private int? _hoveredMessageId;
    private int? _emojiPickerMessageId;

    // ── Compose ──
    private string _newMessage = string.Empty;

    // ── Lifecycle ──
    protected override async Task OnInitializedAsync()
    {
        _channels = await ChatService.GetChannelsAsync();
        if (_channels?.Count > 0)
        {
            await SelectChannelAsync(_channels[0]);
        }
    }

    // ── Channel selection ──
    private async Task SelectChannelAsync(Channel channel)
    {
        if (_activeChannelId == channel.Id) return;

        _activeChannelId = channel.Id;
        _activeChannel = channel;
        _skip = 0;
        _allLoaded = false;
        _messages = null;
        _threadSummaries.Clear();
        CloseThread();

        var msgs = await ChatService.GetMessagesAsync(channel.Id, 0, PageSize);
        _messages = msgs;
        _skip = msgs.Count;

        BuildThreadSummaries(msgs);

        await ChatService.MarkChannelReadAsync(channel.Id);
        await RefreshChannelListAsync();
    }

    private async Task RefreshChannelListAsync()
    {
        _channels = await ChatService.GetChannelsAsync();
    }

    // ── Pagination on scroll-to-top ──
    private async Task OnMainScrollAsync()
    {
        // JS interop would be ideal here; as a pragmatic fallback we load more
        // when the user triggers the handler near the top. In a production app,
        // inject IJSRuntime to read scrollTop.
        if (_loadingMore || _allLoaded || _messages is null) return;
        await LoadOlderMessagesAsync();
    }

    private async Task LoadOlderMessagesAsync()
    {
        if (_activeChannelId is null) return;

        _loadingMore = true;
        StateHasChanged();

        var older = await ChatService.GetMessagesAsync(_activeChannelId.Value, _skip, PageSize);
        if (older.Count == 0)
        {
            _allLoaded = true;
        }
        else
        {
            _messages!.InsertRange(0, older);
            _skip += older.Count;
            BuildThreadSummaries(older);
        }

        _loadingMore = false;
    }

    // ── Sending messages ──
    private async Task SendMessageAsync()
    {
        if (string.IsNullOrWhiteSpace(_newMessage) || _activeChannelId is null) return;

        var sent = await ChatService.SendMessageAsync(_activeChannelId.Value, _newMessage.Trim(), null);
        _messages ??= new();
        _messages.Add(sent);
        _skip++;
        _newMessage = string.Empty;
    }

    private async Task OnComposeKeyDownAsync(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await SendMessageAsync();
        }
    }

    // ── Thread panel ──
    private async Task OpenThreadAsync(Message rootMessage)
    {
        _threadRootMessage = rootMessage;
        _threadReplies = await ChatService.GetThreadAsync(rootMessage.Id);
        _threadReplyText = string.Empty;
        _threadOpen = true;
    }

    private void CloseThread()
    {
        _threadOpen = false;
        _threadRootMessage = null;
        _threadReplies = null;
        _threadReplyText = string.Empty;
    }

    private async Task SendThreadReplyAsync()
    {
        if (string.IsNullOrWhiteSpace(_threadReplyText) || _threadRootMessage is null || _activeChannelId is null) return;

        var reply = await ChatService.SendMessageAsync(_activeChannelId.Value, _threadReplyText.Trim(), _threadRootMessage.Id);
        _threadReplies ??= new();
        _threadReplies.Add(reply);
        _threadReplyText = string.Empty;

        // Update the summary count in the main list
        if (_threadSummaries.TryGetValue(_threadRootMessage.Id, out var existing))
        {
            _threadSummaries[_threadRootMessage.Id] = existing with { ReplyCount = existing.ReplyCount + 1, LastReplyAt = reply.SentAt };
        }
        else
        {
            _threadSummaries[_threadRootMessage.Id] = new ThreadSummary(_threadRootMessage.Id, 1, reply.SentAt);
        }
    }

    private async Task OnThreadReplyKeyDownAsync(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await SendThreadReplyAsync();
        }
    }

    // ── Reactions ──
    private async Task AddReactionAsync(int messageId, string emoji)
    {
        await ChatService.AddReactionAsync(messageId, emoji);
        _emojiPickerMessageId = null;

        // Refresh the visible messages to pick up reaction changes
        if (_activeChannelId is not null && _messages is not null)
        {
            var refreshed = await ChatService.GetMessagesAsync(_activeChannelId.Value, 0, _skip);
            _messages = refreshed;
        }

        if (_threadRootMessage is not null)
        {
            _threadReplies = await ChatService.GetThreadAsync(_threadRootMessage.Id);
        }
    }

    private void ToggleEmojiPicker(int messageId)
    {
        _emojiPickerMessageId = _emojiPickerMessageId == messageId ? null : messageId;
    }

    // ── Thread summary helpers ──
    private void BuildThreadSummaries(List<Message> messages)
    {
        // Identify messages that are replied-to by other messages in the loaded set.
        var replyGroups = messages
            .Where(m => m.ReplyToId is not null)
            .GroupBy(m => m.ReplyToId!.Value);

        foreach (var g in replyGroups)
        {
            var count = g.Count();
            var lastReply = g.Max(m => m.SentAt);
            if (_threadSummaries.TryGetValue(g.Key, out var prev))
            {
                _threadSummaries[g.Key] = new ThreadSummary(g.Key, prev.ReplyCount + count,
                    lastReply > prev.LastReplyAt ? lastReply : prev.LastReplyAt);
            }
            else
            {
                _threadSummaries[g.Key] = new ThreadSummary(g.Key, count, lastReply);
            }
        }
    }

    // ── Formatting helpers ──
    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt.ToUniversalTime();
        return diff.TotalSeconds switch
        {
            < 60 => "just now",
            < 3600 => $"{(int)diff.TotalMinutes} min ago",
            < 86400 => $"{(int)diff.TotalHours}h ago",
            < 604800 => $"{(int)diff.TotalDays}d ago",
            _ => sentAt.ToString("MMM d, yyyy")
        };
    }

    private static string Truncate(string text, int maxLen) =>
        text.Length <= maxLen ? text : string.Concat(text.AsSpan(0, maxLen), "…");
}

